		case NOT:
			output << "not\n";
            break;
         default:
            output << "\n";
      }
    }
	else
	{
      //output<<"Binary op is : "<<n->op_;

	  if (n->left_!=NULL)
		 n->left_->accept(codeRight);

	  if (n->right_!=NULL)
		 n->right_->accept(codeRight);

	  switch ( n->op_ )
	  {
		case ADD:
			output << "add i\n";
            break;
		case MIN:
            output << "sub i\n";
            break;
		case MUL:
			output << "mul i\n";
            break;
        case AND:
            output << "and\n";
            break;
		case OR:
			output << "or\n";
            break;
		case EQU:
            output << "equ i\n";
            break;
		case GEQ:
            output << "geq i\n";
            break;
        case LEQ:
            output << "leq i\n";
            break;
		case LES:
			output << "les i\n";
            break;
		case GRE:
            output << "grt i\n";
            break;
		case NEQ:
            output << "neq i\n";
            break;
         default:
            output << "\n";
      }

    }

